import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.VxKNwi4m.js";const c=JSON.parse('{"title":"건별 납부 관리","description":"","frontmatter":{},"headers":[],"relativePath":"payment/manage.md","filePath":"payment/manage.md","lastUpdated":1783943221000}'),i={name:"payment/manage.md"};function n(d,t,o,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="건별-납부-관리" tabindex="-1">건별 납부 관리 <a class="header-anchor" href="#건별-납부-관리" aria-label="Permalink to &quot;건별 납부 관리&quot;">​</a></h1><p>특정 계약자의 납부 일정을 관리하고, 개별 입금 내역을 등록, 수정 및 증명서를 발급하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>계약 납부 관리 &gt; 건별 납부 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>선택된 계약자의 전체 분양 대금 납부 계획(약정액)과 실제 수납 현황을 대조하여 미납액을 파악하고, 개별 수납 데이터를 관리합니다. 수납 내역을 바탕으로 납부 확인서 및 연체료 내역서 등 각종 대외 증명 서류를 출력할 수 있습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li>계약자 검색 및 상세 납부 정보 로드</li><li>회차별 납부 약정일, 약정금액, 수납금액 및 미(과오)납 현황 대조</li><li>개별 수납 내역 등록, 수정, 삭제 (분할 납부 지원)</li><li>입금액과 장부 분개 금액 간의 일치 여부 검증</li><li>납부 확인서(일반/확인용), 할인/가산금 내역서, 일자별 연체료 내역서 PDF 출력</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-계약-건-찾기" tabindex="-1">1. 계약 건 찾기 <a class="header-anchor" href="#_1-계약-건-찾기" aria-label="Permalink to &quot;1. 계약 건 찾기&quot;">​</a></h3><p>성명, 일련번호 등을 통해 관리 대상 계약자를 선택합니다.</p><ul><li><strong>기능</strong>: 검색어 입력 후 [계약 건 찾기] 버튼 클릭 시 검색 결과가 버튼 형태로 나열되며, 클릭 시 해당 계약자의 납부 현황이 로드됩니다.</li><li><strong>정보 표시</strong>: 선택된 계약자의 일련번호, 타입, 동호수 정보를 상단 알림창에 표시합니다.</li></ul><h3 id="_2-납부-현황-보드-우측-영역" tabindex="-1">2. 납부 현황 보드 (우측 영역) <a class="header-anchor" href="#_2-납부-현황-보드-우측-영역" aria-label="Permalink to &quot;2. 납부 현황 보드 (우측 영역)&quot;">​</a></h3><p>해당 계약자의 전체 납부 계획과 현재까지의 성과를 실시간으로 비교하여 보여줍니다.</p><h4 id="주요-표시-항목" tabindex="-1">주요 표시 항목 <a class="header-anchor" href="#주요-표시-항목" aria-label="Permalink to &quot;주요 표시 항목&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">항목</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">납부기일</td><td style="text-align:left;">각 회차별 납부 약정일 (계약일 및 설정된 경과일수 기반 자동 산출)</td></tr><tr><td style="text-align:left;">구분</td><td style="text-align:left;">납부 회차 명칭 (계약금, 중도금, 잔금 등)</td></tr><tr><td style="text-align:left;">약정금액</td><td style="text-align:left;">시스템 설정에 따라 산출된 회차별 납부 의무 금액</td></tr><tr><td style="text-align:left;">수납금액</td><td style="text-align:left;">실제로 입금되어 해당 회차에 배정된 금액의 합계</td></tr><tr><td style="text-align:left;">미(과오)납</td><td style="text-align:left;">(수납금액 - 약정금액) 결과. 음수(빨간색)는 미납, 양수(파란색)는 과오납 의미</td></tr></tbody></table><h3 id="_3-수납-내역-관리-좌측-영역" tabindex="-1">3. 수납 내역 관리 (좌측 영역) <a class="header-anchor" href="#_3-수납-내역-관리-좌측-영역" aria-label="Permalink to &quot;3. 수납 내역 관리 (좌측 영역)&quot;">​</a></h3><p>실제 입금된 내역을 목록으로 확인하고 관리합니다.</p><h4 id="주요-기능-1" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능-1" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h4><ul><li><strong>신규 납부 등록</strong>: 새로운 입금 내역을 추가합니다.</li><li><strong>수정 및 확인</strong>: 목록의 금액이나 [보기] 버튼을 클릭하여 상세 내용을 수정합니다.</li><li><strong>차수 분할 등록</strong>: 하나의 은행 입금 건을 여러 회차(예: 2차 계약금 + 업무대행비)로 나누어 등록할 수 있습니다.</li><li><strong>계약 건 변경</strong>: 등록된 수납 내역을 현재 계약자에게서 분리하여 [납부 내역 관리]로 되돌립니다. (오등록 수정 시 사용)</li></ul><h3 id="_4-납부-확인서-및-증명서-발급" tabindex="-1">4. 납부 확인서 및 증명서 발급 <a class="header-anchor" href="#_4-납부-확인서-및-증명서-발급" aria-label="Permalink to &quot;4. 납부 확인서 및 증명서 발급&quot;">​</a></h3><p>상단 툴팁 영역에서 다양한 PDF 문서를 생성할 수 있습니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">문서 종류</th><th style="text-align:left;">설명</th></tr></thead><tbody><tr><td style="text-align:left;">납부 확인서 (일반용)</td><td style="text-align:left;">미납 내역 및 연체/가산 정보를 포함한 공식 납부 증명서</td></tr><tr><td style="text-align:left;">납부 확인서 (확인용)</td><td style="text-align:left;">연체 정보 없이 실제 수납된 내역만 깨끗하게 표시하는 확인서</td></tr><tr><td style="text-align:left;">일자별 연체료</td><td style="text-align:left;">입금 시점별로 계산된 상세 연체료 산출 근거 내역서</td></tr><tr><td style="text-align:left;">할인/가산금 내역</td><td style="text-align:left;">(특정 프로젝트) 선납 할인 및 연체 가산금 종합 내역서</td></tr></tbody></table><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="금액-검증-로직" tabindex="-1">금액 검증 로직 <a class="header-anchor" href="#금액-검증-로직" aria-label="Permalink to &quot;금액 검증 로직&quot;">​</a></h3><p>수납 등록 시 **[은행 거래 금액]**과 하단 **[회차별 분할 금액의 합계]**가 반드시 일치해야 저장이 가능합니다. 시스템은 실시간으로 차액을 계산하여 사용자에게 안내합니다.</p><h3 id="수정-제한-90일-규칙" tabindex="-1">수정 제한 (90일 규칙) <a class="header-anchor" href="#수정-제한-90일-규칙" aria-label="Permalink to &quot;수정 제한 (90일 규칙)&quot;">​</a></h3><p>데이터의 무결성을 위해 수납일(거래일)로부터 <strong>90일이 경과한 데이터</strong>는 일반 권한으로 수정이나 삭제가 불가능합니다. 기간이 지난 데이터의 수정이 필요한 경우 시스템 관리자에게 문의해야 합니다.</p>',27)])])}const x=a(i,[["render",n]]);export{c as __pageData,x as default};
